/// <summary>
/// Resubmit button should be invisible if WorkflowStatus is Rejected.
/// </summary>
/// <returns>int</returns>
public int active()
{

    int ret = next active();

    FormRun formRun = this.formRun();
    FormFunctionButtonControl resubmitButton = formRun.design().controlName("WorkflowAction1") as FormFunctionButtonControl;
    FormFunctionButtonControl cancelButton = formRun.design().controlName("WorkflowAction2") as FormFunctionButtonControl;
    ETGSalesEditLines etgLine = this.cursor();

    if (etgLine.WorkflowStatus == ETGSalesEditLinesWorkflow::Rejected)
    {
        if (resubmitButton)
        {
            resubmitButton.visible(false);
        }
        if (cancelButton)
        {
            cancelButton.visible(false);
        }
    }
    else
    {
        if (resubmitButton)
        {
            resubmitButton.visible(true);
        }
        else
        {
            cancelButton.visible(false);
        }
    }
    return ret;

}
